    isActive: true,
    skills: ["vocabulary"],
    transcript: [
      { id: "izon-dc-172-1", startTime: 0, endTime: 3, text: "mịẹ́sèiyé", translation: { en: "guilt (=mịẹseí) [mịẹ́ sèí+yé]" } },
      { id: "izon-dc-172-2", startTime: 3, endTime: 6, text: "mịẹ́²", translation: { en: "come to the surface of the water to take air or food (of fishes) (= sọ́ụ)" } },
      { id: "izon-dc-172-3", startTime: 6, endTime: 9, text: "mọ nị", translation: { en: "or: Indií mọ̀ nị náma àáà? Is it fish or meat?" } },
      { id: "izon-dc-172-4", startTime: 9, endTime: 12, text: "mọ...mọ", translation: { en: "(tonal enclitics) and: Ẹgbẹ mọ, Aláere mọ̀ Ẹgbẹ and Alaere" } },
      { id: "izon-dc-172-5", startTime: 12, endTime: 15, text: "mọmọ", translation: { en: "(tonal enclitic) and; with (form of mọ² ‘with’ and the second part of mọ...mọ ‘and’, used after short pronoun in second position in sentence) : Áràụ́ ị̀mọmọ bonghími. She will come with me: N mọ ị mọ́mọ mu. Let me and you go." } },
      { id: "izon-dc-172-6", startTime: 15, endTime: 18, text: "mọnghọmọnghọ́", translation: { en: "very fleshy and fine: ọngọ́ sẹ̀ mọnghọmọ nghọ́ The whole body is fleshy and fine." } },
      { id: "izon-dc-172-7", startTime: 18, endTime: 21, text: "mọtọọ", translation: { en: "fine-looking, as the smooth body of a child (<motoo)" } },
      { id: "izon-dc-172-8", startTime: 21, endTime: 24, text: "mọ²", translation: { en: "(tonal enclitic) with (cf. mọmọ): Erí wò ta mọ́ bomi. He came with his wife. -mọ³ def. (tonal enclitic) the (plural): wárịmọ the houses -mọ4 v.suff. (tonal enclitic) (adds causative meaning to verb): bóu drink; bóumọ cause to drink -mọ5 suff. (tonal enclitic) (creates adverbs): mẹẹn quiet and slow; mẹẹnmọ́ quietly and slowly" } },
      { id: "izon-dc-172-9", startTime: 24, endTime: 27, text: "mọ¹", translation: { en: "(tone always low, requires an immediately preceding high) A. as soon as; when: Fị́sìín mọ̀, ọ mumí. When they had finished eating, they went; B. if: N bánghìị̣́ mọ̀, ye i kpótudọ If you run, I will chase you." } },
      { id: "izon-dc-172-10", startTime: 27, endTime: 30, text: "mọ́ kpọ̀", translation: { en: "still, yet: Erí mọ kpọ̀ naá bogha He has still not come yet. mọ́ mìẹ̣ kọ because of this action: Áràụ́ mọ mìẹ̣ kọ, wónì a tókonimi Because of her action, we praised her." } },
      { id: "izon-dc-172-11", startTime: 30, endTime: 33, text: "mọ́ngọ̀", translation: { en: "mug; cup [<English mug]" } },
      { id: "izon-dc-172-12", startTime: 33, endTime: 36, text: "mọ́²", translation: { en: "(used to show that object has been put at beginning of sentence): Kẹnị́òbori tọbọụ ọ mọọ́ ẹ̀rịmị. It was a kid that they saw. -mọ́³ v.suff. towards; against (directional suffix): Tị́nbị nị̀ụ sẹsẹ́rẹmọ. Lean the stick against him." } },
      { id: "izon-dc-172-13", startTime: 36, endTime: 39, text: "mọ́¹", translation: { en: "thus; like this; so; mọ́ kị this way: Wó mọ kị mìẹ̣ mị́ẹdọ aba, ebighá If we do it like this, it is not good: Mọ́ kị èmi It’s like this: mọ́ kị̀then; moreover; so; now Wó ye fị sìndọ ába, mọ́ kị̀wó siidọ When we have finished eating, then we will go to farm; mọ́ kpọ̀ still; yet; mọ́ mìẹ̣ do thus; do like this; mọ́bị [meaning?]: Mọ́bị pàadọ́ aba If (it) happens so...; mọ́ mìẹ̣ mị́ẹ/mọ́ tìmi tími such as this: Wónì naá mọ mìẹ̣ míẹ̣ yè ẹrịgha. We have never seen such a thing as this before.; mọ́ tìmidẹ́ị kị/mọ wẹ̀rịdẹ́ị kị just wait, wait for a while" } },
      { id: "izon-dc-172-14", startTime: 39, endTime: 42, text: "mọ́ọnmọọn", translation: { en: "fairly acceptable; interesting" } },
      { id: "izon-dc-172-15", startTime: 42, endTime: 45, text: "mọụnkorú", translation: { en: "famine; starvation; fasting: Mọụnkorubí èbighá. Starvation is not good; mọụnkoru kụ́ràị year of famine: Mọụnkoru kụ́ràị ya, gbún (ụyan) kị fịyemèé In a year of famine, wild beans are eaten." } },
      { id: "izon-dc-172-16", startTime: 45, endTime: 48, text: "mọụ́n", translation: { en: "scarcity, shortage, of foodstuff; famine; hunger (cf. ụkpán): Béi amà mọụn koro káamị There is a great shortage of foodstuff in this town: Mọụ́n ị̀ kọrịyémi/Arị́mọụ̀́ n kọ̀rịyemí I am hungry; mọụn iné endure hunger; mọụn korú be short of food or starving for an extended period; fast: Erí mọ̀ụn koruyémi He is fasting." } },
      { id: "izon-dc-172-17", startTime: 48, endTime: 51, text: "mụkẹmụkẹ́", translation: { en: "beaming; with a radiant smile or look of pleasure (<mukemuké)" } },
      { id: "izon-dc-172-18", startTime: 51, endTime: 54, text: "mụlẹmụlẹ́", translation: { en: "light; soft" } },
      { id: "izon-dc-172-19", startTime: 54, endTime: 57, text: "mụlẹị́", translation: { en: "A. move slowly and gracefully, as by a plump person during dancing or walking; B. roll slowly, as by a smoothbodied fish on a smooth surface (e.g. mudfish in a canoe)" } },
      { id: "izon-dc-172-20", startTime: 57, endTime: 60, text: "mụmụmụụ́", translation: { en: "painful; with a feeling of serious heat (from fire) (=gbịị́n)" } },
      { id: "izon-dc-172-21", startTime: 60, endTime: 63, text: "mụnẹmụnẹ́", translation: { en: "soft and weak-bodied; describes a weakling or sickly person" } },
      { id: "izon-dc-172-22", startTime: 63, endTime: 66, text: "mụnịíị̣̀", translation: { en: "flexible, as a kitten or cat" } },
      { id: "izon-dc-172-23", startTime: 66, endTime: 69, text: "mụrẹnmụrẹ́n² (=mụnrẹnmụnrẹ́n)", translation: { en: "with a smile on the face; keeping cheerful all the time mụrụụ" } },
      { id: "izon-dc-172-24", startTime: 69, endTime: 72, text: "mụrẹnmụrẹ́n¹ (=mụnrẹnmụnrẹ́n)", translation: { en: "describes a smouldering heat, as from fire" } },
      { id: "izon-dc-172-25", startTime: 72, endTime: 75, text: "mụsẹmụsẹ́", translation: { en: "keeping a half smile on the face all the time mụụ" } },
    ],
