    transcript: [
      { id: "izon-dc-181-1", startTime: 0, endTime: 3, text: "odú-òpotou", translation: { en: "flower of ịzọ́n-odu, the old cocoyam [odú + ?]" } },
      { id: "izon-dc-181-2", startTime: 3, endTime: 6, text: "odúbàụ", translation: { en: "cocoyam tuber [odú + baụ́ daughter]" } },
      { id: "izon-dc-181-3", startTime: 6, endTime: 9, text: "odúbèri", translation: { en: "cocoyam leaf [odú + berí leaf]" } },
      { id: "izon-dc-181-4", startTime: 9, endTime: 12, text: "odúbèrí", translation: { en: "sting-ray (Dasyatis spp.) [odú + berí leaf (from the shape?)] (=sị́ka)" } },
      { id: "izon-dc-181-5", startTime: 12, endTime: 15, text: "odúbùrú", translation: { en: "A. a children’s game played during the yam harvesting season. Two children agree in the presence of a third person to call on each other’s name. One scores or wins a point when the person called answers oó (which is the more honoured answer by custom). But when the person answers in any other form, such as ẹíṇ or teyáà or ụụ́n, no score is made. The winner is the first person to make seven points. The loser then roasts a very nice water-yam for the winner, which should be eaten on a well-swept floor watched by others. The yam is carried and supported by the two hands, but not placed on any plate. If any crumb(s) drops on the floor, the yam is shared by all. If no crumb falls, the loser continues on different days until seven yams have been so roasted; B. the yam so roasted [odú + burú yam]" } },
      { id: "izon-dc-181-6", startTime: 15, endTime: 18, text: "odúfị̀dọn", translation: { en: "chest pain, usually associated with the effect of eating ‘old’ cocoyam with fresh pepper [odú + fị́eat + dọọ́n pain]" } },
      { id: "izon-dc-181-7", startTime: 18, endTime: 21, text: "odúgbòró", translation: { en: "twisting line or shape; illegible handwriting; squiggle" } },
      { id: "izon-dc-181-8", startTime: 21, endTime: 24, text: "odútị̀bị", translation: { en: "cocoyam corm [odú + tị́bị head]" } },
      { id: "izon-dc-181-9", startTime: 24, endTime: 27, text: "odúuduu", translation: { en: "bird, probably the Hadada Ibis (Bostrychia hagedash THRESKIORNITHIDAE)" } },
      { id: "izon-dc-181-10", startTime: 27, endTime: 30, text: "odú²", translation: { en: "white of egg" } },
      { id: "izon-dc-181-11", startTime: 30, endTime: 33, text: "odú¹", translation: { en: "cocoyam (all types from family ARACEAE); beké-òdu new or imported cocoyam (Xanthosoma mafaffa Schott.); bou-odú inedible wild species (Rhektophyllum mirabile N.E. Br.); ekúeodu [describe!]; Isélema-odu a strong reddish cocoyam from Warri; ịzọ́n-odu old cocoyam (Colocasia esculenta (Linn.) Schott.); owéi-odu male cocoyam which does not produce tubers" } },
      { id: "izon-dc-181-12", startTime: 33, endTime: 36, text: "ofiyoú", translation: { en: "whirlpool; eddy" } },
      { id: "izon-dc-181-13", startTime: 36, endTime: 39, text: "ofoló", translation: { en: "bonga-fish or bonga shad, from brackish-water areas, sold on racks (Ethmalosa fimbriata Bowdich CLUPEIDAE) (=abáneri =kígbo²)" } },
      { id: "izon-dc-181-14", startTime: 39, endTime: 42, text: "ofomú", translation: { en: "heavy breathing, panting, usually after a strenuous job or running" } },
      { id: "izon-dc-181-15", startTime: 42, endTime: 45, text: "ofomúkọ̀rịghá (=ofomukọrịghá)", translation: { en: "medicinal climber on trees or shrubs with thick round leaves used for fever and to give strength for wrestling or hard work [ofomú + kọrị́ catch -gha not]" } },
      { id: "izon-dc-181-16", startTime: 45, endTime: 48, text: "oforontanịghá (=ofonrontanaghá)", translation: { en: "purlin" } },
      { id: "izon-dc-181-17", startTime: 48, endTime: 51, text: "ofukú²", translation: { en: "a style of hair-plaiting in which no thread is used, associated particularly with priestesses and with the Okpotu festival; ofuku dụnụ́ plait in the ofukú style" } },
      { id: "izon-dc-181-18", startTime: 51, endTime: 54, text: "ofukú¹", translation: { en: "bellows" } },
      { id: "izon-dc-181-19", startTime: 54, endTime: 57, text: "ofurumofú", translation: { en: "bladder (of fish); lungs (of humans and animals)" } },
      { id: "izon-dc-181-20", startTime: 57, endTime: 60, text: "ofé (=ofó)", translation: { en: "(also ofédọn) asthma" } },
      { id: "izon-dc-181-21", startTime: 60, endTime: 63, text: "oféfè", translation: { en: "weak, empty (usually in a derogatory sense); oféfè kịmị an ineffective, lightweight person" } },
      { id: "izon-dc-181-22", startTime: 63, endTime: 66, text: "ofían²", translation: { en: "yam shaped like a broom" } },
      { id: "izon-dc-181-23", startTime: 66, endTime: 69, text: "ofían³", translation: { en: "an expression willing an evil event not to happen, or averting an imminent evil; ofían-òfian yọụmọ́ tụ̀a Don’t fear, advance (nothing will happen) (phrase used in traditional maritime warfare)" } },
      { id: "izon-dc-181-24", startTime: 69, endTime: 72, text: "ofían¹", translation: { en: "broom (cf. ịlị́a, ọfị́nye)" } },
      { id: "izon-dc-181-25", startTime: 72, endTime: 75, text: "ofínyo-gbọ̀lụbáụ", translation: { en: "masquerader with no mask on his head; in other respects, he is dressed in the same way as other dancers wrestling before going to the farm (or it would kill the crops) [odú + báa kill + burú yam + báa kill] [check tone]" } },
    ],
