    transcript: [
      { id: "izon-dc-235-1", startTime: 0, endTime: 3, text: "tein-á-sụọgha", translation: { en: "name of a medicine which protects the owner from gunshots [teín¹ + ya when + sú¢¢o¢¢gha does not enter; i.e. when shot, doesn’t enter]" } },
      { id: "izon-dc-235-2", startTime: 3, endTime: 6, text: "teintuó", translation: { en: "herb (Diodia scandens Sw. RUBIACEAE) [teín³ + túo herb]" } },
      { id: "izon-dc-235-3", startTime: 6, endTime: 9, text: "tekeléè", translation: { en: "disproportionate, with the upper body bigger than the lower (>tẹkẹlẹẹ́̀)" } },
      { id: "izon-dc-235-4", startTime: 9, endTime: 12, text: "teketeké", translation: { en: "unsteadily, as a toddler: Erí ìne ẹ́rị̀bị, teketeke kí bànghị bómi When he saw me, he came running unsteadily towards me." } },
      { id: "izon-dc-235-5", startTime: 12, endTime: 15, text: "tekpeé", translation: { en: "top-heavy with big head" } },
      { id: "izon-dc-235-6", startTime: 15, endTime: 18, text: "tekuú", translation: { en: "well-shaped; bulky; well-balanced" } },
      { id: "izon-dc-235-7", startTime: 18, endTime: 21, text: "telefómù", translation: { en: "A. telephone; B. rumour-monger; one who gossips; tale-bearer [<English telephone] (=telefónù)" } },
      { id: "izon-dc-235-8", startTime: 21, endTime: 24, text: "telefónù", translation: { en: "A. telephone; B. rumour-monger; one who gossips; tale-bearer [<English telephone] (=telefómù)" } },
      { id: "izon-dc-235-9", startTime: 24, endTime: 27, text: "temí", translation: { en: "pound; díri temi pound medicine; ụtáràn temi pound fufu" } },
      { id: "izon-dc-235-10", startTime: 27, endTime: 30, text: "tengbelee", translation: { en: "with a big swelling or distension (>tẹngbẹlẹẹ)" } },
      { id: "izon-dc-235-11", startTime: 30, endTime: 33, text: "tenghetenghé", translation: { en: "jelly-like (of large object) (>te¢nghe¢te¢nghé¢)" } },
      { id: "izon-dc-235-12", startTime: 33, endTime: 36, text: "teribịbị́", translation: { en: "cover [terí + bị́bị mouth]" } },
      { id: "izon-dc-235-13", startTime: 36, endTime: 39, text: "teriiyé", translation: { en: "shelter (e.g. umbrella, mat) [terií + yé thing] [or teriyé?] terimọ́ v.dir. cover up (moving something with the hands): Ọtọ́kọ̀ naá bùrumọ́ tèrimọ Cover the yams with earth. [terí + -mọ́ directional]" } },
      { id: "izon-dc-235-14", startTime: 39, endTime: 42, text: "terií", translation: { en: "be closed; cover (place) thickly (as yam vines): Buru kirí tèriídọ The yam farm is thriving. [terí + í process]" } },
      { id: "izon-dc-235-15", startTime: 42, endTime: 45, text: "terí", translation: { en: "A. cover; close: bẹ́lẹ tèri cover the pot: wárịbọọ̀ teri close the door; buru terí germinate yams on the ground by covering them with mown grass; líị̣ terì A. cover a palm bunch carefully on top of the palm tree to prevent it from dropping any of its ripe fruits to attract other palm cutters (=líị̣ ònyoma); B. cover smoked or sun-dried palm-fruits in the akpórogù with plantain leaves to soften them through fermenting. This was the method used before boiling was introduced. After the palm fruits so softened have been crushed with the feet and enough boiling water has been added, the paste is covered again to allow the oil to drip off; terighá èlemulemu beni uncovered well-water; B. crown: Ọrọ amánanaowei tun nì u teridọ́ They have crowned him (with a king’s crown)." } },
      { id: "izon-dc-235-16", startTime: 45, endTime: 48, text: "terínìmíkùtu", translation: { en: "(geom.) closed shape [terí + nìmí present state + kútu piece]" } },
      { id: "izon-dc-235-17", startTime: 48, endTime: 51, text: "tesií", translation: { en: "be flattened (as of head of a person); tesiínìmí tị̀bị flattened head: Wo tịbịbị́tèsi kí èmi His head is flattened." } },
      { id: "izon-dc-235-18", startTime: 51, endTime: 54, text: "teuu (=teuú=teu=teú)", translation: { en: "not too high or low; average: Wárị ùtu sẹ teu kí èmi The roof of the house is not too low. (>tẹụụ)" } },
      { id: "izon-dc-235-19", startTime: 54, endTime: 57, text: "teí", translation: { en: "expose; reveal; teí bàmọ́ kpọ̀ faá with no concern; Erí ìne egbérì naa bi¢, teí bàmọ́ kpọ̀ faá When he heard what happened to me, he treated it with levity; tiri teí expose; ịmọlọụ́̀ tiri teí let the tongue hang out" } },
      { id: "izon-dc-235-20", startTime: 57, endTime: 60, text: "teín4", translation: { en: "mottle; spot; toru teín mark with chalk: Óru sẹị erema tòru teinyémi The woman dancing for a deity is putting spots on her body with chalk; tein yọwẹ́ị paddle decorated with dots of different colours; ẹdụlẹ (=ọdịlẹ) toru téìn apply native chalk of different colours mixed with water to a deceased person customarily and ceremoniously, as formerly done at Kaiama for those whose totem is leopard" } },
      { id: "izon-dc-235-21", startTime: 60, endTime: 63, text: "teín5", translation: { en: "(in tops) a set of three pieces" } },
      { id: "izon-dc-235-22", startTime: 63, endTime: 66, text: "teín²", translation: { en: "play (game that involves pieces, e.g. tops, draughts)" } },
      { id: "izon-dc-235-23", startTime: 66, endTime: 69, text: "teín³", translation: { en: "sting (of bee, ant, etc.); shock, as electricity or electric fish; cause to itch (of poisoned water, grass, fresh yam peelings, etc.): Túomọ ìne ọngọ́ tèinmi The grass is making me itch; ogbóru tèín be in a quarrelsome mood" } },
      { id: "izon-dc-235-24", startTime: 69, endTime: 72, text: "teín¹", translation: { en: "shoot; hunt; atángbà tein injure by magically ‘shooting’ the victim; inject poison from one’s own body into someone else’s body; bou teín A. hunt for game; B. be poisoned by the bush (believed to be done by some evil spirits, such as osúowèi)" } },
      { id: "izon-dc-235-25", startTime: 72, endTime: 75, text: "tibú", translation: { en: "incitement; tibú tụ̀a inflame: Tibú tụ̀a naá yee sèimọ kụmọ eé Don’t inflame the situation to make matters worse. tié shortened form of te yé, see te" } },
    ],
