    transcript: [
      { id: "izon-dc-248-1", startTime: 0, endTime: 3, text: "tẹ́mẹ4", translation: { en: "A. shadow: Tọbọụbị́wò tẹmẹbị́ ọ̀wẹi banghịmị́ The boy ran away from his shadow in fear; B. (tech.) [or general?] reflection; image; silhouette; tẹ́mẹ mịẹ paamọ reflect (as mirror); C. spirit; ghost; apparition: Erí bòu ghọ́ kịmị tẹmẹ ẹrịmị He saw a ghost in the bush; tẹ́mẹ bì warị́ the house where a girl’s soul desires to be circumcised or a person who is sick wishes to be; tẹ́mẹ biye what one’s spirit demands, i.e. things that should be done before circumcision or delivery, etc., as revealed by divination tẹ́mẹ dụ̀dụ kọrị́ A. embrace and welcome someone, usually a dear person, such as a member of the family (lit. ‘let souls hold each other’); B. drink together as a sign of re-union of souls; tẹ́mẹ ọ̀fọíṇ deathconscious; mindful of death; kị́mị tẹmẹ person’s ghost/spirit Tẹ́mẹaraụ n.f. God (‘she who creates’); (= Wóyenghi, Ayíba, Áyòú, Ogínaaraụ, Súoaraụ /Soaráụ Zibaaraụ) [tẹ́mẹ¹ + araụ female agent]" } },
      { id: "izon-dc-248-2", startTime: 3, endTime: 6, text: "tẹ́mẹdii (=tẹ́mẹdiiye)", translation: { en: "mirror" } },
      { id: "izon-dc-248-3", startTime: 6, endTime: 9, text: "tẹ́mẹdiiye (=tẹ́mẹdii)", translation: { en: "mirror [tẹ́mẹ 4B + dií look at + yé thing]" } },
      { id: "izon-dc-248-4", startTime: 9, endTime: 12, text: "tẹ́mẹsuo", translation: { en: "collective spirit of a social entity, expressed in a formal praise-title (i.e. the ‘spirit-form’ that envelopes the group); amátẹmẹsuo collective spirit of a town, expressed in its formal praise-title; bíritẹmẹsuo collective spirit of a quarter, ward, expressed in its formal praise-title; ibetẹmẹsúo collective spirit of an ibeé or ‘clan’, expressed in its formal praise-title [tẹ́mẹ4C + suó form]" } },
      { id: "izon-dc-248-5", startTime: 12, endTime: 15, text: "tẹ́mẹtọnmọye", translation: { en: "model [tẹ́mẹ 4B + tọ́nmọ compare + yé thing]" } },
      { id: "izon-dc-248-6", startTime: 15, endTime: 18, text: "tẹ́mẹzụọye", translation: { en: "salvation [tẹ́mẹ4C + zụọ́ save + yé thing]" } },
      { id: "izon-dc-248-7", startTime: 18, endTime: 21, text: "tẹ́mẹ²", translation: { en: "(often dụ́wẹị tẹmẹ) honour the dead by shooting guns, dancing and telling stories after the deceased has been buried: Erí dàụ tẹmẹyémi He is honouring his dead father." } },
      { id: "izon-dc-248-8", startTime: 21, endTime: 24, text: "tẹ́mẹ³", translation: { en: "appease (for sexual offence); bou tẹmẹ́ perform a ceremony as a peace sacrifice for the bush when any male and female human beings have sexual intercourse in the bush where fowls (cock and hen) are absent (the bush is desecrated if a couple have sexual intercourse in the bush without having a cock and hen with them); kíri tẹmẹ̀ perform a ceremony to appease the earth when sexual intercourse is done on the bare ground" } },
      { id: "izon-dc-248-9", startTime: 24, endTime: 27, text: "tẹ́mẹ¹", translation: { en: "A. create: Wóyenghi ki wo tẹ̀mẹmị It is God who created us; B. mould; form; shape; manufacture; mint (coin) : Arị́ẹ̀pẹ́tẹ̀ kịmị tẹmẹtọ́ I have moulded a clay man; C. fabricate, make up (story): Kị́mị ègberí tẹ̀mẹ kụ́mọ, páa bara kị̀dii gbá Don’t make up a story, state it as it happened." } },
      { id: "izon-dc-248-10", startTime: 27, endTime: 30, text: "tẹ́mụtẹ̀mụ", translation: { en: "describes the slow movement of a fat person; waddling" } },
      { id: "izon-dc-248-11", startTime: 30, endTime: 33, text: "tẹ́rẹ-yèi, tẹ́rẹ-tàa-yarị́", translation: { en: "children’s game in which a boy is borne by his playmates to his play-wife [tẹ́rẹ² + yeí husband + tẹ́rẹ² + taá wife + yarị́send]" } },
      { id: "izon-dc-248-12", startTime: 33, endTime: 36, text: "tẹ́rẹyaị", translation: { en: "palm-leaf supporting the bunch; (fig.) (of woman) buttocks; rump [tẹ́rẹ¹ + yaị things]" } },
      { id: "izon-dc-248-13", startTime: 36, endTime: 39, text: "tẹ́rẹ²", translation: { en: "love very dearly: Erí à tẹ́rẹ kị nị̀a tẹ́rẹ wonìmí He loves her very dearly." } },
      { id: "izon-dc-248-14", startTime: 39, endTime: 42, text: "tẹ́rẹ³", translation: { en: "deep affection: Tamaá tẹrẹ kọọ̀ emí His wife is (held) in deep affection." } },
      { id: "izon-dc-248-15", startTime: 42, endTime: 45, text: "tẹ́rẹ¹", translation: { en: "A. heave up; carry (heavy object) in hands for short distance; B. support: Utu tịnmọ́ kị̀utuú tẹ̀rẹ wónìmí It is the major house-posts that are holding up the roof." } },
      { id: "izon-dc-248-16", startTime: 45, endTime: 48, text: "tẹ́rụụ", translation: { en: "describes a very high flood: Bowei bení sẹ̀ tẹ́rụụ kị èmí The flood is very high; (of container) full to the brim" } },
      { id: "izon-dc-248-17", startTime: 48, endTime: 51, text: "tẹ́tẹbụ̀rẹ́ (=ètẹ́tẹbụ̀rẹ́)", translation: { en: "Laughing Dove (Streptopelia senegalensis COLUMBIDAE) [check id]" } },
      { id: "izon-dc-248-18", startTime: 51, endTime: 54, text: "tẹ́tẹmọ", translation: { en: "use caution; be mindful, as when treating delicate issues, or when handling delicate things; use with care a dilapidated object that is almost worn out: Ungúbi pẹ̀ị́ dụ̀rị́nìmí, ụ tẹtẹmọ́ kọ̀rị́ The pitcher is almost broken, so handle it with care [What is dụrí?̣ not found under D; check tone]; (fig.) handle in such a way that an already complicated matter or condition is not worsened [sentence example]" } },
      { id: "izon-dc-248-19", startTime: 54, endTime: 57, text: "tẹ́tẹrẹntẹ̀tẹrẹn", translation: { en: "extremely tired and not finding it easy to continue working, wrestling, fighting or any other activity" } },
      { id: "izon-dc-248-20", startTime: 57, endTime: 60, text: "tẹ́ẹrụtẹ̀ẹrụ", translation: { en: "describes the movement of a short or dwarfish bow-legged person, or of an ordinary small child" } },
      { id: "izon-dc-248-21", startTime: 60, endTime: 63, text: "tẹ́ẹ²", translation: { en: "prayer [Check tone class] tẹẹrẹẹ́ v.a. be round, circular, and not too big (<teereé)" } },
      { id: "izon-dc-248-22", startTime: 63, endTime: 66, text: "tẹ́ẹ¹", translation: { en: "beg; implore; pray [?tone class]" } },
      { id: "izon-dc-248-23", startTime: 66, endTime: 69, text: "tẹ́ịnmọ4", translation: { en: "(usu. tẹ́ịnmọ (páa)) a style of women’s blouse with a loose open neck" } },
      { id: "izon-dc-248-24", startTime: 69, endTime: 72, text: "tẹ́ịnmọdeì", translation: { en: "rectangular frame triggered baited floating hook; floating snaphook [tẹ́ịnmọ¹ + déi hook]" } },
      { id: "izon-dc-248-25", startTime: 72, endTime: 75, text: "tẹ́ịnmọdiì", translation: { en: "floating net [tẹ́ịnmọ¹ + díi net]" } },
    ],
