    transcript: [
      { id: "izon-dc-324-1", startTime: 0, endTime: 3, text: "ịsụ́n¹", translation: { en: "plant (yam) so that the earth under the newly developing yam is dug out and covered up lightly to make the soil more porous for the yam to grow down and enlarge; ịsụ́n burù yam planted by this method" } },
      { id: "izon-dc-324-2", startTime: 3, endTime: 6, text: "ịtalị́", translation: { en: "midges (Culicoides) [check id]" } },
      { id: "izon-dc-324-3", startTime: 6, endTime: 9, text: "ịtághaị", translation: { en: "rash on the human body; okírikà ịtaghaị temporary rash at the base of the hair on the body as a result of cold [?goose pimples]; omóun ị̀taghaị heat rash resulting from sweat" } },
      { id: "izon-dc-324-4", startTime: 9, endTime: 12, text: "ịtákpà", translation: { en: "many small marks made on children; a tattoo mark on the face; a horizontal stroke below the eye" } },
      { id: "izon-dc-324-5", startTime: 12, endTime: 15, text: "ịtánị", translation: { en: "leaves of young palm tree" } },
      { id: "izon-dc-324-6", startTime: 15, endTime: 18, text: "ịtátaịn", translation: { en: "something which hangs about in flakes or patches (usu. specified as below); bou ịtátàịn moss (Taxithelium rotundatulum (C. Müll.) Broth.); éri ịtataịn soot; wárị ị̀tataịn dirt hanging from eaves" } },
      { id: "izon-dc-324-7", startTime: 18, endTime: 21, text: "ịtáịnkọlị (=atáịnkọlị)", translation: { en: "something which comes to nothing after a long struggle; illusion; vain hope" } },
      { id: "izon-dc-324-8", startTime: 21, endTime: 24, text: "ịtáụ̀²=ịtáụ=táụ̀", translation: { en: "grand(child) [check tone & cf. táu1tò1bo1ú11)" } },
      { id: "izon-dc-324-9", startTime: 24, endTime: 27, text: "ịtáụ̀¹", translation: { en: "sucker (e.g. of plantain); shoot; scion; ịtáụ sòu remove suckers from main plant; beriba ịtáụ plantain sucker" } },
      { id: "izon-dc-324-10", startTime: 27, endTime: 30, text: "ịtị́onrịn", translation: { en: "silky headtie" } },
      { id: "izon-dc-324-11", startTime: 30, endTime: 33, text: "ịtị́àíṇ", translation: { en: "sunbird (general name) (NECTARINIDAE) (cf. ịsọ́sọ̀ for the smallest type)" } },
      { id: "izon-dc-324-12", startTime: 33, endTime: 36, text: "ịtẹtẹ́rẹ̀ (=ị́tẹ̀tẹ́rẹ̀)", translation: { en: "melon, smaller than egúsi and ogírì, with small seeds which are fried before being pounded for soup. The fruits and the seeds move from smallest to largest as ịtẹtẹ́rẹ̀, egúsi and ogírì; the seeds of both ịtẹtẹ́rẹ̀ and egúsi are bought in a semiprepared state as ogírì." } },
      { id: "izon-dc-324-13", startTime: 36, endTime: 39, text: "ịtọlọ́²", translation: { en: "sandfly (PHLEBOBOTOMIDAE)" } },
      { id: "izon-dc-324-14", startTime: 39, endTime: 42, text: "ịtọlọ́¹", translation: { en: "small tree with flexible twigs; it has ‘male’ and ‘female’ varieties (both identified as Glyphaea brevis (Spreng.) Monachino TILIACEAE)" } },
      { id: "izon-dc-324-15", startTime: 42, endTime: 45, text: "ịtọ́bọị", translation: { en: "young palm tree which has not yet developed any sort of stem (cf. asará); ịtọ́bọị pomu young palm-leaf ịtọ́ịn see ịtọ́nghị (=ịtọ́ngị)" } },
      { id: "izon-dc-324-16", startTime: 45, endTime: 48, text: "ịtọ́nghị (=ịtọ́ngị =ịtọ́ịn)", translation: { en: "fish (Chromodotilapia sp? güntheri) [Family?]" } },
      { id: "izon-dc-324-17", startTime: 48, endTime: 51, text: "ịtọ́nlẹị", translation: { en: "dew; (fig.) ịtọ́nlẹị kan be one’s mother’s first child: Erí/Áràú1 ịtọ́nlẹị kan He/She is the mother’s first child (lit. ‘walking through dew’)." } },
      { id: "izon-dc-324-18", startTime: 51, endTime: 54, text: "ịvalíị̣̀", translation: { en: "? having the top or tip cut off, and thus abnormally short" } },
      { id: "izon-dc-324-19", startTime: 54, endTime: 57, text: "ịvịadọọ́n", translation: { en: "hot flushes and pain related to the menopause" } },
      { id: "izon-dc-324-20", startTime: 57, endTime: 60, text: "ịvịlịváà", translation: { en: "very short (as cutlass)" } },
      { id: "izon-dc-324-21", startTime: 60, endTime: 63, text: "ịvịá", translation: { en: "a sacred broom prepared with the leaves of a salt water herb, used by women diviners as one of their emblems" } },
      { id: "izon-dc-324-22", startTime: 63, endTime: 66, text: "ịwawáịn (=ịwawáị̀n)", translation: { en: "straggling shrub growing between sandbank and dry land; ir resembles ịgbánagbanà sensitive plant (Acacia kamerunensis) but is not sensitive, has no thorns, and has hairy stems [specimen?]" } },
      { id: "izon-dc-324-23", startTime: 66, endTime: 69, text: "ịwẹsị́(=ẹwẹsí)̣", translation: { en: "tassel; silky threads in a cob of maize, usu. aká ị̀wẹsị" } },
      { id: "izon-dc-324-24", startTime: 69, endTime: 72, text: "ịwịrị́", translation: { en: "pubic hair (male or female) (contrast dúma, táma)" } },
      { id: "izon-dc-324-25", startTime: 72, endTime: 75, text: "ịwọ́nrọnrọn", translation: { en: "tree (Pauridiantha hirtella (Benth.) Bremek. RUBIACEAE); dirimaịwọ́nrọ̀nrọn shrub (Psychotria psychotrioides (DC.) Roberty RUBIACEAE)" } },
    ],
