    order: 341,
    isActive: true,
    skills: ["vocabulary"],
    transcript: [
      { id: "izon-dc-341-1", startTime: 0, endTime: 3, text: "ụmbaụfíòu (=ụmbaụfíyòu)", translation: { en: "rest" } },
      { id: "izon-dc-341-2", startTime: 3, endTime: 6, text: "ụmbánà (=ụbánà)", translation: { en: "thank you" } },
      { id: "izon-dc-341-3", startTime: 6, endTime: 9, text: "ụmbọmbọọ́", translation: { en: "describes a situation when many animals are seen sitting together with their heads bent, or many children on their knees close together" } },
      { id: "izon-dc-341-4", startTime: 9, endTime: 12, text: "Ụmbọ́kọ (=Ọmbọ́kọ)", translation: { en: "Ibibio; Ụmbọ́kọ-otu Ibibio people" } },
      { id: "izon-dc-341-5", startTime: 12, endTime: 15, text: "ụmbọ́tọọ", translation: { en: "many and close together, as when heads of many fish like ụlụ́ma appear in the gbére (fish hole)" } },
      { id: "izon-dc-341-6", startTime: 15, endTime: 18, text: "ụmbụ-tụa-kị́mị̀", translation: { en: "hunchback" } },
      { id: "izon-dc-341-7", startTime: 18, endTime: 21, text: "ụmbụ́bụrụ", translation: { en: "murmur quietly, sometimes grumbling ụmbụkụụ" } },
      { id: "izon-dc-341-8", startTime: 21, endTime: 24, text: "ụmbụ́kụ-ụ̀mbụkụ", translation: { en: "describes a fairly short and fat person walking with head bent down ụmbụlụụ" } },
      { id: "izon-dc-341-9", startTime: 24, endTime: 27, text: "ụmbụụ́", translation: { en: "hunch; hump; ụmbụ tụá be hunchbacked: Ụmbụ tụá ère ịkịyọ́ụ kị̀akị yei mọ angámị A hunch-backed wife takes care how she lives with her husband (saying used when someone works with another for a long time and studies them to know how they react)." } },
      { id: "izon-dc-341-10", startTime: 27, endTime: 30, text: "ụndụ́dụ̀", translation: { en: "spike (=témiye) [?<Igbo ńdụ̀dụ́ skewer] ụndụkụụ" } },
      { id: "izon-dc-341-11", startTime: 30, endTime: 33, text: "ụndụ́rụmà", translation: { en: "[?] mysterious; hard to understand; ụndụ́rụmà bibi unexpected trouble" } },
      { id: "izon-dc-341-12", startTime: 33, endTime: 36, text: "ụndụ́²", translation: { en: "life; living: Ụndụ́ laa ye fà There’s nothing like life. [cf. Igbo ńdụ̀ life]" } },
      { id: "izon-dc-341-13", startTime: 36, endTime: 39, text: "ụndụ́¹", translation: { en: "live" } },
      { id: "izon-dc-341-14", startTime: 39, endTime: 42, text: "ụngbará", translation: { en: "shin" } },
      { id: "izon-dc-341-15", startTime: 42, endTime: 45, text: "ụngbálụ̀", translation: { en: "type of tree used in building houses ụngbalụụ" } },
      { id: "izon-dc-341-16", startTime: 45, endTime: 48, text: "ụngbárà", translation: { en: "baton; club" } },
      { id: "izon-dc-341-17", startTime: 48, endTime: 51, text: "ụngbẹẹ", translation: { en: "reputed, famous, an expert, an adept ụngbụlụụ" } },
      { id: "izon-dc-341-18", startTime: 51, endTime: 54, text: "ụngbẹẹ́", translation: { en: "A. iron spike: (saying) ụngbẹ fẹíṇ nì ụbọ inénghì ghọ tụ́a keep torturing or taunting a person who is in a fix (lit. put a red-hot spike up someone’s anus); B. crafty person [is this the same word? Cf. ụngbẹẹ]" } },
      { id: "izon-dc-341-19", startTime: 54, endTime: 57, text: "ụngbọ́tụa", translation: { en: "name of a game ụngbụfụụ" } },
      { id: "izon-dc-341-20", startTime: 57, endTime: 60, text: "ụngbọ́²", translation: { en: "(always in combination) significant; important: ụngbọ́ egberi significant story: ụngbọ́ bịbị important word; kị́mị ụngbọ distinguished person: Kị́mị ụngbọama kị ị̀mọ dọụ́̀ yémi I am looking for distinguished people." } },
      { id: "izon-dc-341-21", startTime: 60, endTime: 63, text: "ụngbọ́¹", translation: { en: "A. (general term) nut of various trees: eré-ụngbọ (Mucuna pruriens var. utilis (Wight) Burck, c.vars.) [uses?]; ịzọ́nụngbọ [refer to what? uses?]; okúlèí-ụ̀ngbọ (Dioclea reflexa Hook.f., Mucuna flagellipes Hook.f., M. poggei Taub.) used for games, (all LEGUMINOSAEPAPILIONIOIDEAE); líị̣ ụngbọ̀ palm-nut; B. hence, from the shape, cube (as of sugar); dice; lidó ụ̀ngbọ dice; súgà ụngbọ cube of sugar; tọ́rụ ụ̀ngbọ eyeball" } },
      { id: "izon-dc-341-22", startTime: 63, endTime: 66, text: "ụngbụ́mọ", translation: { en: "endure; forbear; bear up: Kị́mị ye nì ị mị́ẹdọụ aba, ụngbụ́mọ wẹrị mìẹ̣ naa akị́ If someone treats you (badly), endure (without showing your feelings and taking revenge)." } },
      { id: "izon-dc-341-23", startTime: 66, endTime: 69, text: "ụngọ́", translation: { en: "money; wealth; tị́bị ụngọ bridewealth; ‘brideprice’ (=tị́bị saa)" } },
      { id: "izon-dc-341-24", startTime: 69, endTime: 72, text: "ụngọ́warị", translation: { en: "shop; store [ụngọ́ + wárị house]" } },
      { id: "izon-dc-341-25", startTime: 72, endTime: 75, text: "ụngụlị́", translation: { en: "silver catfish (Chrysichthys spp., including nigrodigitatus BAGRIDAE); ụngụlị mini tụ́à look better as a result of good feeding [?]; sei ụngụ́lị̀ silver catfish which looks lean and ugly when it comes out from holes where it has been feeding its young ụ́ngụọ" } },
    ],
